const handleDateChange = async (task: Task, children: Task[]) => {
  // Validate date change
  if (task.end < task.start) {
    toast.error('End date cannot be before start date');
    return false; // Reject change
  }

  // Update backend
  try {
    await updateTaskDates(task.id, task.start, task.end);
    toast.success('Task updated');
    return true; // Accept change
  } catch (error) {
    toast.error('Failed to update task');
    return false; // Reject change
  }
};

const handleProgressChange = async (task: Task, children: Task[]) => {
  await updateTaskProgress(task.id, task.progress);
};

